#!/usr/bin/env node
/**
 * generate-react-query-hooks — Tier 6: generates TanStack Query hooks wrapping
 * the generated client.
 *
 * DOMAIN-PARTITIONED (feature-1781435713420-506r2pr8i): hooks are split into
 * domain-scoped chunks that mirror the client chunks. Each hook chunk star-imports
 * ONLY its sibling client chunk (`../manifest-client/<domain>.generated`), so a
 * CRM page pulls the crm client chunk — not the kitchen/payroll monolith.
 *
 * Output layout (DO NOT EDIT):
 *   apps/app/app/lib/manifest-hooks.generated.ts        (shim → re-exports barrel)
 *   apps/app/app/lib/manifest-hooks/core.generated.ts   (global queryKeys factory)
 *   apps/app/app/lib/manifest-hooks/<domain>.generated.ts (useQuery/useMutation for that domain)
 *   apps/app/app/lib/manifest-hooks/index.generated.ts  (barrel)
 *
 * Usage:
 *   node manifest/scripts/generate-react-query-hooks.mjs [--outdir <path>]
 */
import { existsSync, mkdirSync, readFileSync, writeFileSync } from "node:fs";
import { dirname, join, resolve } from "node:path";
import {
  CLIENT_CHUNKS,
  resolveClientChunk,
} from "./entity-domain-map.mjs";

const IR_PATH = resolve("manifest/ir/kitchen.ir.json");
const CLIENT_DIR = resolve("apps/app/app/lib/manifest-client");

// Parse args
const args = process.argv.slice(2);
let outDir = resolve("apps/app/app/lib");
for (let i = 0; i < args.length; i++) {
  if (args[i] === "--outdir" && args[i + 1]) {
    outDir = resolve(args[i + 1]);
    i++;
  }
}

if (!existsSync(IR_PATH)) {
  console.error(`IR not found at ${IR_PATH}. Run pnpm manifest:compile first.`);
  process.exit(1);
}
if (!existsSync(CLIENT_DIR)) {
  console.error(
    `Partitioned client not found at ${CLIENT_DIR}. Run manifest:client first.`
  );
  process.exit(1);
}

// Load IR to get entity names and command info
const ir = JSON.parse(readFileSync(IR_PATH, "utf-8"));
const entities = ir.entities ?? [];
console.log(`Loaded IR: ${entities.length} entities`);

// Helper: PascalCase to camelCase
function toCamelCase(str) {
  return str[0].toLowerCase() + str.slice(1);
}

// Per-domain exported client functions (parse each chunk so a hook only emits
// when its sibling client chunk actually exposes the list/get fn).
const RUNTIME_CHUNKS = CLIENT_CHUNKS.filter((c) => c !== "core");
const clientFnsByChunk = {};
function loadChunkFns(chunkName) {
  const file = join(CLIENT_DIR, `${chunkName}.generated.ts`);
  if (!existsSync(file)) {
    return new Set();
  }
  const src = readFileSync(file, "utf8");
  const fns = new Set();
  for (const m of src.matchAll(/export async function (\w+)/g)) {
    fns.add(m[1]);
  }
  return fns;
}
// Core chunk also exposes cross-domain callers (collaboration, admin, ...).
const coreClientFns = loadChunkFns("core");
for (const ch of RUNTIME_CHUNKS) {
  clientFnsByChunk[ch] = loadChunkFns(ch);
}
console.log(
  `Loaded client fns: core=${coreClientFns.size}, ` +
    RUNTIME_CHUNKS.map((c) => `${c}=${clientFnsByChunk[c].size}`).join(", ")
);

// Group IR entities by client chunk. Entities not in ENTITY_DOMAIN_MAP resolve
// to "core" (keeps current behavior: their mutation hooks still emit via executeCommand).
const chunkEntities = Object.fromEntries(
  CLIENT_CHUNKS.map((c) => [c, []])
);
const chunkTypes = Object.fromEntries(CLIENT_CHUNKS.map((c) => [c, new Set()]));
for (const entity of entities) {
  const ch = resolveClientChunk(entity.name);
  chunkEntities[ch].push(entity);
  chunkTypes[ch].add(entity.name);
}

// ─── queryKeys factory block (defined ONCE, in core) ───────────────────────
// queryKeys is cheap (constant string-array tuples, no network) and is referenced
// by every domain hook file for cache invalidation, so it is DEFINED in core and
// IMPORTED by the domain chunks.
const hooksDir = join(outDir, "manifest-hooks");
mkdirSync(hooksDir, { recursive: true });

const queryKeysBlock = [
  "/**",
  " * Query key factory for all Manifest entities.",
  " * Usage: queryKeys.entityName.lists() / queryKeys.entityName.detail(id)",
  " */",
  "export const queryKeys = {",
];
for (const entity of entities) {
  const c = toCamelCase(entity.name);
  queryKeysBlock.push(`  ${c}: {`);
  queryKeysBlock.push(`    all: ["${c}"] as const,`);
  queryKeysBlock.push(`    lists: () => [...queryKeys.${c}.all, "list"] as const,`);
  queryKeysBlock.push(
    `    detail: (id: string) => [...queryKeys.${c}.all, "detail", id] as const,`
  );
  queryKeysBlock.push("  },");
}
queryKeysBlock.push("} as const;");

// ─── Per-domain hook chunks ────────────────────────────────────────────────
const summary = { list: 0, detail: 0, mutation: 0 };
const writeDomainChunk = (chunkName, chunkEntityList, clientFns, isCore) => {
  const lines = [
    `// GENERATED by manifest:generate-hooks — DO NOT EDIT. Domain chunk: ${chunkName}.`,
    `// Star-imports ONLY this domain's client chunk so the bundle excludes other domains.`,
  ];
  if (isCore) {
    lines.push(
      '// Core: DEFINES queryKeys (sibling domain chunks import it from here).'
    );
  }
  lines.push(
    'import { useQuery, useMutation, useQueryClient, type UseQueryOptions, type UseMutationOptions } from "@tanstack/react-query";'
  );
  lines.push(
    `import * as client from "../manifest-client/${chunkName}.generated";`
  );
  lines.push(
    `import type { PaginatedResponse } from "../manifest-client/core.generated";`
  );
  lines.push(
    `import { executeCommand, type CommandEnvelope } from "../manifest-client";`
  );
  if (!isCore) {
    // Domain chunks import queryKeys from the core hook chunk.
    lines.push(`import { queryKeys } from "./core.generated";`);
  }
  // Type-import line is filled in after emission — only types actually
  // referenced by an emitted hook are imported (mixin "entities" like
  // SoftDeletable/TenantScoped have no hooks and would be unused imports).
  const typeImportIndex = lines.length;
  lines.push(null);
  const usedTypes = new Set();
  lines.push("");

  if (isCore) {
    // Define queryKeys inline (no self-import).
    lines.push(...queryKeysBlock);
    lines.push("");
  }

  let listCount = 0;
  let detailCount = 0;
  let mutationCount = 0;
  const skippedList = [];
  const skippedDetail = [];

  // List hooks
  lines.push("// List hooks (useEntityList)");
  for (const entity of chunkEntityList) {
    const name = entity.name;
    const camel = toCamelCase(name);
    const listFn = `list${name}s`;
    if (!clientFns.has(listFn)) {
      skippedList.push(name);
      continue;
    }
    listCount++;
    usedTypes.add(name);
    lines.push(`export function use${name}List(`);
    lines.push(
      `  options?: Omit<UseQueryOptions<PaginatedResponse<${name}>, Error>, "queryKey" | "queryFn">,`
    );
    lines.push(") {");
    lines.push("  return useQuery({");
    lines.push(`    queryKey: queryKeys.${camel}.lists(),`);
    lines.push(`    queryFn: () => client.${listFn}(),`);
    lines.push("    staleTime: 30_000,");
    lines.push("    ...options,");
    lines.push("  });");
    lines.push("}");
    lines.push("");
  }

  // Detail hooks
  lines.push("// Detail hooks (useEntityDetail)");
  for (const entity of chunkEntityList) {
    const name = entity.name;
    const camel = toCamelCase(name);
    const getFn = `get${name}`;
    if (!clientFns.has(getFn)) {
      skippedDetail.push(name);
      continue;
    }
    detailCount++;
    usedTypes.add(name);
    lines.push(`export function use${name}Detail(`);
    lines.push("  id: string,");
    lines.push(
      `  options?: Omit<UseQueryOptions<${name} | undefined, Error>, "queryKey" | "queryFn">,`
    );
    lines.push(") {");
    lines.push("  return useQuery({");
    lines.push(`    queryKey: queryKeys.${camel}.detail(id),`);
    lines.push(`    queryFn: () => client.${getFn}(id),`);
    lines.push("    enabled: !!id,");
    lines.push("    staleTime: 30_000,");
    lines.push("    ...options,");
    lines.push("  });");
    lines.push("}");
    lines.push("");
  }

  // Command mutation hooks
  lines.push("// Command mutation hooks (useEntityCommandNameMutation)");
  for (const entity of chunkEntityList) {
    const entityName = entity.name;
    const entityCamel = toCamelCase(entityName);
    const commands = entity.commands ?? [];
    for (const cmd of commands) {
      const cmdName = typeof cmd === "string" ? cmd : cmd.name;
      const cmdPascal = cmdName[0].toUpperCase() + cmdName.slice(1);
      const hookName = `use${entityName}${cmdPascal}Mutation`;
      mutationCount++;
      usedTypes.add(entityName);
      lines.push(`export function ${hookName}(`);
      lines.push(
        `  options?: Omit<UseMutationOptions<CommandEnvelope<${entityName}>, Error, Record<string, unknown>>, "mutationFn">,`
      );
      lines.push(") {");
      lines.push("  const queryClient = useQueryClient();");
      lines.push("  return useMutation({");
      lines.push(
        `    mutationFn: (input) => executeCommand<${entityName}>("${entityName}", "${cmdName}", input),`
      );
      lines.push("    onSuccess: () => {");
      lines.push(
        `      queryClient.invalidateQueries({ queryKey: queryKeys.${entityCamel}.all });`
      );
      lines.push("    },");
      lines.push("    ...options,");
      lines.push("  });");
      lines.push("}");
      lines.push("");
    }
  }

  summary.list += listCount;
  summary.detail += detailCount;
  summary.mutation += mutationCount;
  const importableTypes = [...chunkTypes[chunkName]]
    .filter((t) => usedTypes.has(t))
    .sort();
  if (importableTypes.length > 0) {
    lines[typeImportIndex] =
      `import type { ${importableTypes.join(", ")} } from "../manifest-types.generated";`;
  } else {
    lines.splice(typeImportIndex, 1);
  }
  writeFileSync(join(hooksDir, `${chunkName}.generated.ts`), lines.join("\n"));
  return { listCount, detailCount, mutationCount, skippedList, skippedDetail };
};

// Core hook chunk: DEFINES queryKeys + cross-domain entity hooks (uses core client fns).
const coreRes = writeDomainChunk("core", chunkEntities.core, coreClientFns, true);
// Runtime domain chunks IMPORT queryKeys from core.
const domainResults = {};
for (const ch of RUNTIME_CHUNKS) {
  domainResults[ch] = writeDomainChunk(
    ch,
    chunkEntities[ch],
    clientFnsByChunk[ch],
    false
  );
}

// ─── index.generated.ts (barrel) ───────────────────────────────────────────
const indexLines = [
  "// GENERATED by manifest:generate-hooks — DO NOT EDIT. Barrel.",
  'export * from "./core.generated";',
];
for (const ch of RUNTIME_CHUNKS) {
  indexLines.push(`export * from "./${ch}.generated";`);
}
writeFileSync(join(hooksDir, "index.generated.ts"), indexLines.join("\n") + "\n");

// ─── Backward-compat shim ──────────────────────────────────────────────────
const shimPath = resolve(outDir, "manifest-hooks.generated.ts");
writeFileSync(
  shimPath,
  [
    "// GENERATED by manifest:generate-hooks — DO NOT EDIT.",
    "// Backward-compat shim: re-exports the domain-partitioned barrel.",
    'export * from "./manifest-hooks/index.generated";',
  ].join("\n") + "\n"
);

// ─── Summary ───────────────────────────────────────────────────────────────
const fmt = (r) =>
  `list=${r.listCount} detail=${r.detailCount} mut=${r.mutationCount}`;
console.log(`WROTE ${join(hooksDir, "core.generated.ts")} (queryKeys + core hooks: ${fmt(coreRes)})`);
for (const ch of RUNTIME_CHUNKS) {
  console.log(`WROTE ${join(hooksDir, ch + ".generated.ts")} (${fmt(domainResults[ch])})`);
}
console.log(`WROTE ${join(hooksDir, "index.generated.ts")} (barrel)`);
console.log(`WROTE ${shimPath} (shim)`);
console.log(
  `TOTAL list=${summary.list} detail=${summary.detail} mutation=${summary.mutation}`
);
